{"tool":"newFileCreated","path":"frontend/src/components/NazoratchiPanel.jsx","content":"import React, { useState, useEffect } from 'react';
import { Calendar, ChevronLeft, ChevronRight, Target, BarChart3, Save, RefreshCw } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const DAYS = ['Dush', 'Sesh', 'Chor', 'Pay', 'Jum', 'Shan', 'Yak'];
const DAYS_FULL = ['Dushanba', 'Seshanba', 'Chorshanba', 'Payshanba', 'Juma', 'Shanba', 'Yakshanba'];

function getMonday(d) {
  const date = new Date(d);
  const day = date.getDay();
  const diff = date.getDate() - day + (day === 0 ? -6 : 1);
  date.setDate(diff);
  return date.toISOString().split('T')[0];
}

const NazoratchiPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [restDays, setRestDays] = useState([]);
  const [weekStart, setWeekStart] = useState(getMonday(new Date()));
  const [activeTab, setActiveTab] = useState('plan'); // 'plan' or 'report'

  // Daily Plan state
  const [planDate, setPlanDate] = useState(new Date().toISOString().split('T')[0]);
  const [dailyPlans, setDailyPlans] = useState({});
  const [planInputs, setPlanInputs] = useState({});
  const [saving, setSaving] = useState(false);

  // Monthly Report state
  const [reportMonth, setReportMonth] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  });
  const [monthlyData, setMonthlyData] = useState(null);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const fetchData = async () => {
    try {
      const [opsRes, asgRes, restRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/assignments`, { headers }),
        fetch(`${API}/rest-days?week_start=${weekStart}`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (asgRes.ok) setAssignments(await asgRes.json());
      if (restRes.ok) setRestDays(await restRes.json());
    } catch (e) {}
  };

  const fetchDailyPlans = async () => {
    try {
      const res = await fetch(`${API}/daily-plans?date=${planDate}`, { headers });
      if (res.ok) {
        const plans = await res.json();
        const planMap = {};
        const inputMap = {};
        plans.forEach(p => {
          const key = `${p.operator_id}-${p.machine_id}`;
          planMap[key] = p;
          inputMap[key] = p.plan_meters;
        });
        setDailyPlans(planMap);
        setPlanInputs(inputMap);
      }
    } catch (e) {}
  };

  const fetchMonthlyReport = async () => {
    try {
      const res = await fetch(`${API}/reports/monthly/excel?month=${reportMonth}`, { headers });
      if (res.ok) {
        // The endpoint returns Excel file, but we need JSON data for display
        // Let's create a separate endpoint for JSON monthly report
        // For now, we'll use the daily-plans endpoint to build the report client-side
        const [year, month] = reportMonth.split('-').map(Number);
        const daysInMonth = new Date(year, month, 0).getDate();

        // Fetch all plans for the month
        const plansRes = await fetch(`${API}/daily-plans?date=${reportMonth}`, { headers });
        if (plansRes.ok) {
          const plans = await plansRes.json();
          const opMap = {};

          // Initialize operator data
          operators.filter(o => o.is_active && o.position === 'Operator').forEach(op => {
            opMap[op.id] = {
              name: op.name,
              days: {},
              totalPlan: 0,
              totalActual: 0
            };
          });

          // Fill in plan data
          plans.forEach(p => {
            if (opMap[p.operator_id]) {
              const day = parseInt(p.date.split('-')[2]);
              if (!opMap[p.operator_id].days[day]) {
                opMap[p.operator_id].days[day] = { plan: 0, actual: 0 };
              }
              opMap[p.operator_id].days[day].plan += p.plan_meters;
              opMap[p.operator_id].days[day].actual += p.actual_meters;
              opMap[p.operator_id].totalPlan += p.plan_meters;
              opMap[p.operator_id].totalActual += p.actual_meters;
            }
          });

          setMonthlyData({ operators: opMap, daysInMonth });
        }
      }
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, [weekStart]);
  useEffect(() => { fetchDailyPlans(); }, [planDate]);
  useEffect(() => { 
    if (activeTab === 'report') fetchMonthlyReport(); 
  }, [reportMonth, activeTab, operators]);

  useEffect(() => { 
    const h = () => fetchData(); 
    window.addEventListener('app-refresh', h); 
    return () => window.removeEventListener('app-refresh', h); 
  }, [weekStart]);

  const toggleRestDay = async (operatorId, dayOfWeek) => {
    try {
      await fetch(`${API}/rest-days`, {
        method: 'POST', headers,
        body: JSON.stringify({ operator_id: operatorId, day_of_week: dayOfWeek, week_start: weekStart })
      });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const isResting = (opId, dow) => restDays.some(r => r.operator_id === opId && r.day_of_week === dow);

  const shiftWeek = (offset) => {
    const d = new Date(weekStart);
    d.setDate(d.getDate() + offset * 7);
    setWeekStart(d.toISOString().split('T')[0]);
  };

  const weekLabel = () => {
    const start = new Date(weekStart);
    const end = new Date(weekStart);
    end.setDate(end.getDate() + 6);
    return `${start.toLocaleDateString('uz')} - ${end.toLocaleDateString('uz')}`;
  };

  const getOperatorMachines = (operatorId) => {
    return assignments.filter(a => a.operator_id === operatorId && a.is_active === 1);
  };

  const handlePlanChange = (operatorId, machineId, value) => {
    const key = `${operatorId}-${machineId}`;
    setPlanInputs(prev => ({ ...prev, [key]: parseFloat(value) || 0 }));
  };

  const saveDailyPlans = async () => {
    setSaving(true);
    try {
      const plansToSave = [];
      Object.entries(planInputs).forEach(([key, planMeters]) => {
        if (planMeters > 0) {
          const [operatorId, machineId] = key.split('-');
          plansToSave.push({
            operator_id: parseInt(operatorId),
            machine_id: machineId,
            date: planDate,
            plan_meters: planMeters
          });
        }
      });

      if (plansToSave.length > 0) {
        const res = await fetch(`${API}/daily-plans/bulk`, {
          method: 'POST', headers,
          body: JSON.stringify({ date: planDate, plans: plansToSave })
        });
        if (res.ok) {
          alert('Planlar saqlandi!');
          fetchDailyPlans();
          emitRefresh();
        }
      }
    } catch (e) {
      alert('Xatolik yuz berdi');
    } finally {
      setSaving(false);
    }
  };

  const thStyle = { padding: '12px 16px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' };
  const tdStyle = { padding: '12px 16px', fontSize: '0.85rem', fontWeight: 500 };
  const navBtnStyle = { padding: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--panel-border)', borderRadius: '8px', color: 'var(--text-main)', cursor: 'pointer', display: 'flex', alignItems: 'center' };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '12px' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>
          <Calendar size={24} style={{ marginRight: '8px', verticalAlign: 'middle' }} />
          Nazoratchi Paneli
        </h2>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button 
            onClick={() => setActiveTab('plan')} 
            style={{
              padding: '8px 16px', borderRadius: '8px', border: 'none',
              background: activeTab === 'plan' ? 'var(--primary)' : 'rgba(255,255,255,0.05)',
              color: activeTab === 'plan' ? '#0f172a' : 'var(--text-muted)',
              cursor: 'pointer', fontWeight: 600, fontSize: '0.85rem',
              display: 'flex', alignItems: 'center', gap: '6px'
            }}>
            <Target size={16} /> Kunlik Reja
          </button>
          <button 
            onClick={() => setActiveTab('report')} 
            style={{
              padding: '8px 16px', borderRadius: '8px', border: 'none',
              background: activeTab === 'report' ? 'var(--primary)' : 'rgba(255,255,255,0.05)',
              color: activeTab === 'report' ? '#0f172a' : 'var(--text-muted)',
              cursor: 'pointer', fontWeight: 600, fontSize: '0.85rem',
              display: 'flex', alignItems: 'center', gap: '6px'
            }}>
            <BarChart3 size={16} /> Oylik Hisobot
          </button>
        </div>
      </div>

      {activeTab === 'plan' && (
        <>
          {/* Date selector for daily plan */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '1.5rem' }}>
            <label style={{ fontSize: '0.9rem', fontWeight: 600 }}>Sana:</label>
            <input 
              type="date" 
              value={planDate} 
              onChange={e => setPlanDate(e.target.value)}
              className="input-field"
              style={{ width: '180px' }}
            />
            <button 
              onClick={saveDailyPlans}
              disabled={saving}
              style={{
                padding: '8px 16px', borderRadius: '8px', border: 'none',
                background: saving ? 'rgba(34,197,94,0.5)' : '#22c55e',
                color: 'white', cursor: 'pointer', fontWeight: 600,
                display: 'flex', alignItems: 'center', gap: '6px'
              }}>
              {saving ? <RefreshCw size={16} className="animate-spin" /> : <Save size={16} />}
              {saving ? 'Saqlanmoqda...' : 'Saqlash'}
            </button>
          </div>

          {/* Daily plan table */}
          <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden', marginBottom: '2rem' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                  <th style={thStyle}>Operator</th>
                  <th style={thStyle}>Stanok</th>
                  <th style={{ ...thStyle, textAlign: 'center' }}>Reja (metr)</th>
                  <th style={{ ...thStyle, textAlign: 'center' }}>Amal</th>
                </tr>
              </thead>
              <tbody>
                {operators.filter(o => o.is_active && o.position === 'Operator').map(op => {
                  const opMachines = getOperatorMachines(op.id);
                  if (opMachines.length === 0) return null;

                  return opMachines.map((asg, idx) => {
                    const key = `${op.id}-${asg.machine_id}`;
                    const existingPlan = dailyPlans[key];
                    const currentValue = planInputs[key] || '';

                    return (
                      <tr key={key} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                        {idx === 0 && (
                          <td style={tdStyle} rowSpan={opMachines.length}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                              <div style={{
                                width: '32px', height: '32px', borderRadius: '8px',
                                background: 'rgba(0,210,255,0.15)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                fontSize: '0.8rem', fontWeight: 800, color: 'var(--primary)'
                              }}>
                                {op.name.charAt(0).toUpperCase()}
                              </div>
                              <span style={{ fontWeight: 600 }}>{op.name}</span>
                            </div>
                          </td>
                        )}
                        <td style={tdStyle}>
                          <span style={{
                            padding: '4px 8px', borderRadius: '6px', fontSize: '0.75rem',
                            background: 'rgba(168,85,247,0.15)', color: '#a855f7', fontWeight: 600
                          }}>
                            {asg.machine_id}
                          </span>
                        </td>
                        <td style={{ ...tdStyle, textAlign: 'center' }}>
                          <input
                            type="number"
                            value={currentValue}
                            onChange={e => handlePlanChange(op.id, asg.machine_id, e.target.value)}
                            placeholder="0"
                            style={{
                              width: '100px', padding: '6px 10px', borderRadius: '6px',
                              border: '1px solid var(--panel-border)', background: 'rgba(255,255,255,0.03)',
                              color: 'var(--text-main)', textAlign: 'center', fontSize: '0.9rem'
                            }}
                          />
                        </td>
                        <td style={{ ...tdStyle, textAlign: 'center' }}>
                          {existingPlan && (
                            <span style={{
                              padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem',
                              background: existingPlan.status === 'COMPLETED' ? 'rgba(34,197,94,0.15)' : 
                                         existingPlan.status === 'INCOMPLETE' ? 'rgba(239,68,68,0.15)' : 'rgba(245,158,11,0.15)',
                              color: existingPlan.status === 'COMPLETED' ? '#22c55e' : 
                                     existingPlan.status === 'INCOMPLETE' ? '#ef4444' : '#f59e0b',
                              fontWeight: 600
                            }}>
                              {existingPlan.status === 'COMPLETED' ? 'Bajarildi' : 
                               existingPlan.status === 'INCOMPLETE' ? 'Bajarilmadi' : 'Kutilmoqda'}
                            </span>
                          )}
                        </td>
                      </tr>
                    );
                  });
                })}
              </tbody>
            </table>
          </div>
        </>
      )}

      {activeTab === 'report' && (
        <>
          {/* Month selector for monthly report */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '1.5rem' }}>
            <label style={{ fontSize: '0.9rem', fontWeight: 600 }}>Oy:</label>
            <input 
              type="month" 
              value={reportMonth} 
              onChange={e => setReportMonth(e.target.value)}
              className="input-field"
              style={{ width: '180px' }}
            />
          </div>

          {/* Monthly report table */}
          {monthlyData && (
            <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'auto', marginBottom: '2rem' }}>
              <table style={{ borderCollapse: 'collapse', minWidth: '100%' }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                    <th style={{ ...thStyle, position: 'sticky', left: 0, background: '#1e293b', zIndex: 2, minWidth: '140px' }}>Operator</th>
                    {Array.from({ length: monthlyData.daysInMonth }, (_, i) => (
                      <th key={i} style={{ ...thStyle, textAlign: 'center', minWidth: '70px', padding: '4px 2px' }}>{i + 1}</th>
                    ))}
                    <th style={{ ...thStyle, textAlign: 'center', minWidth: '80px' }}>Jami Reja</th>
                    <th style={{ ...thStyle, textAlign: 'center', minWidth: '80px' }}>Jami Bajarildi</th>
                    <th style={{ ...thStyle, textAlign: 'center', minWidth: '60px' }}>%</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(monthlyData.operators).map(([opId, opData]) => {
                    const percentage = opData.totalPlan > 0 
                      ? Math.round((opData.totalActual / opData.totalPlan) * 100) 
                      : 0;

                    return (
                      <tr key={opId} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                        <td style={{ ...tdStyle, position: 'sticky', left: 0, background: '#0f172a', zIndex: 1, fontWeight: 600 }}>
                          {opData.name}
                        </td>
                        {Array.from({ length: monthlyData.daysInMonth }, (_, i) => {
                          const day = i + 1;
                          const dayData = opData.days[day] || { plan: 0, actual: 0 };
                          const dayPercentage = dayData.plan > 0 
                            ? Math.round((dayData.actual / dayData.plan) * 100) 
                            : 0;

                          return (
                            <td key={i} style={{ ...tdStyle, textAlign: 'center', fontSize: '0.75rem' }}>
                              {dayData.plan > 0 ? (
                                <div>
                                  <div style={{ fontWeight: 600 }}>{Math.round(dayData.actual)}/{Math.round(dayData.plan)}</div>
                                  <div style={{ 
                                    color: dayPercentage >= 100 ? '#22c55e' : 
                                           dayPercentage >= 80 ? '#f59e0b' : '#ef4444',
                                    fontWeight: 700
                                  }}>
                                    {dayPercentage}%
                                  </div>
                                </div>
                              ) : '—'}
                            </td>
                          );
                        })}
                        <td style={{ ...tdStyle, textAlign: 'center', fontWeight: 700 }}>
                          {Math.round(opData.totalPlan)}
                        </td>
                        <td style={{ ...tdStyle, textAlign: 'center', fontWeight: 700 }}>
                          {Math.round(opData.totalActual)}
                        </td>
                        <td style={{ 
                          ...tdStyle, textAlign: 'center', fontWeight: 800,
                          color: percentage >= 100 ? '#22c55e' : 
                                 percentage >= 80 ? '#f59e0b' : '#ef4444'
                        }}>
                          {percentage}%
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* Rest days section (always visible) */}
      <div style={{ marginTop: '2rem' }}>
        <h3 style={{ fontSize: '1.1rem', fontWeight: 800, marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <Calendar size={20} /> Dam Olish Jadvali
        </h3>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '1rem' }}>
          <button onClick={() => shiftWeek(-1)} style={navBtnStyle}><ChevronLeft size={16} /></button>
          <span style={{ fontSize: '0.9rem', fontWeight: 700, color: 'var(--primary)', minWidth: '200px', textAlign: 'center' }}>
            {weekLabel()}
          </span>
          <button onClick={() => shiftWeek(1)} style={navBtnStyle}><ChevronRight size={16} /></button>
        </div>
        <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                <th style={thStyle}>Operator</th>
                {DAYS.map((d, i) => (
                  <th key={i} style={{ ...thStyle, textAlign: 'center' }}>{d}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {operators.filter(o => o.is_active).map(op => (
                <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                  <td style={tdStyle}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <div style={{
                        width: '32px', height: '32px', borderRadius: '8px',
                        background: 'rgba(0,210,255,0.15)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: '0.8rem', fontWeight: 800, color: 'var(--primary)'
                      }}>
                        {op.name.charAt(0).toUpperCase()}
                      </div>
                      <span style={{ fontWeight: 600 }}>{op.name}</span>
                    </div>
                  </td>
                  {DAYS.map((_, dow) => {
                    const resting = isResting(op.id, dow);
                    return (
                      <td key={dow} style={{ ...tdStyle, textAlign: 'center' }}>
                        <button
                          onClick={() => toggleRestDay(op.id, dow)}
                          style={{
                            width: '36px', height: '36px', borderRadius: '8px',
                            border: resting ? '2px solid #fbbf24' : '1px solid var(--panel-border)',
                            background: resting ? 'rgba(251,191,36,0.2)' : 'rgba(255,255,255,0.03)',
                            color: resting ? '#fbbf24' : 'var(--text-muted)',
                            cursor: 'pointer', fontSize: '1rem', fontWeight: 700,
                            transition: 'all 0.2s'
                          }}
                          title={DAYS_FULL[dow]}
                        >
                          {resting ? '🛏️' : '○'}
                        </button>
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

