import { Plus, Trash2, Link, Users, UserCheck, Calendar, Download, Target, Save } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const POSITIONS = ['Operator', 'Master', 'Mexanik', 'Uzlavyaz', "Smena boshlig'i"];

const MasterPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [showAddOp, setShowAddOp] = useState(false);
  const [showAssign, setShowAssign] = useState(false);
  const [showAttendance, setShowAttendance] = useState(false);
  const [attendanceMonth, setAttendanceMonth] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  });
  const [attendanceData, setAttendanceData] = useState([]);

  const [opForm, setOpForm] = useState({ name: '', phone: '', position: 'Operator' });
  const [opShift, setOpShift] = useState('KUNDUZ');
  const [selectedOperator, setSelectedOperator] = useState('');
  const [selectedMachines, setSelectedMachines] = useState([]);
  const [shiftType, setShiftType] = useState('KUNDUZ');

  const [restingToday, setRestingToday] = useState([]);

  // Daily plan state
  const [planDate, setPlanDate] = useState(new Date().toISOString().split('T')[0]);
  const [dailyPlans, setDailyPlans] = useState({});
  const [planInputs, setPlanInputs] = useState({});
  const [savingPlan, setSavingPlan] = useState(false);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const isNazoratchi = user.role === 'NAZORATCHI' || user.role === 'ADMIN';

  const fetchData = async () => {
    try {
      const [opsRes, asgRes, restRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/assignments`, { headers }),
        fetch(`${API}/rest-days/today`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (asgRes.ok) setAssignments(await asgRes.json());
      if (restRes.ok) setRestingToday(await restRes.json());
    } catch (e) {}
  };

  const fetchDailyPlans = async () => {
    try {
      const res = await fetch(`${API}/daily-plans?date=${planDate}`, { headers });
      if (res.ok) {
        const plans = await res.json();
        const planMap = {};
        const inputMap = {};
        plans.forEach(p => {
          const key = `${p.operator_id}-${p.machine_id}`;
          planMap[key] = p;
          inputMap[key] = p.plan_meters;
        });
        setDailyPlans(planMap);
        setPlanInputs(inputMap);
      }
    } catch (e) {}
  };

  const fetchAttendance = async () => {
    try {
      const res = await fetch(`${API}/attendance?month=${attendanceMonth}`, { headers });
      if (res.ok) setAttendanceData(await res.json());
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, []);
  useEffect(() => { fetchDailyPlans(); }, [planDate]);
  useEffect(() => { fetchAttendance(); }, [attendanceMonth]);
  useEffect(() => { const h = () => { fetchData(); fetchDailyPlans(); }; window.addEventListener('app-refresh', h); return () => window.removeEventListener('app-refresh', h); }, []);

  const handleAddOperator = async () => {
    if (!opForm.name) return;
    try {
      const res = await fetch(`${API}/operators`, {
        method: 'POST', headers, body: JSON.stringify({ ...opForm, shift_type: opShift })
      });
      if (res.ok) {
        setOpForm({ name: '', phone: '', position: 'Operator' });
        setShowAddOp(false);
        fetchData();
        emitRefresh();
      } else {
        const data = await res.json();
        alert(data.detail || 'Xatolik yuz berdi');
      }
    } catch (e) { alert('Server xatoligi'); }
  };

  const handleDeleteOperator = async (id) => {
    if (!confirm('Ishchini ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/operators/${id}`, { method: 'DELETE', headers });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const toggleMachine = (id) => {
    setSelectedMachines(prev =>
      prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]
    );
  };

  const openAssignForm = (opId, opShiftType) => {
    setSelectedOperator(String(opId));
    setSelectedMachines([]);
    setShiftType(opShiftType || 'KUNDUZ');
    setShowAssign(true);
  };

  const handleAssign = async () => {
    if (!selectedOperator || selectedMachines.length === 0) return;
    try {
      const res = await fetch(`${API}/assignments`, {
        method: 'POST', headers,
        body: JSON.stringify({
          operator_id: parseInt(selectedOperator),
          machine_ids: selectedMachines,
          shift_type: shiftType
        })
      });
      if (res.ok) {
        setSelectedOperator('');
        setSelectedMachines([]);
        setShowAssign(false);
        fetchData();
        emitRefresh();
      }
    } catch (e) {}
  };

  const handleUnassign = async (id) => {
    try {
      await fetch(`${API}/assignments/${id}`, { method: 'DELETE', headers });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const handleSetAttendance = async (workerId, date, status) => {
    try {
      await fetch(`${API}/attendance`, {
        method: 'POST', headers,
        body: JSON.stringify({ worker_id: workerId, date, status })
      });
      fetchAttendance();
    } catch (e) {}
  };

  const exportAttendanceExcel = async () => {
    try {
      const res = await fetch(`${API}/attendance/export?month=${attendanceMonth}`, { headers });
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `tabel_${attendanceMonth}.xlsx`;
        a.click();
        window.URL.revokeObjectURL(url);
      }
    } catch (e) {}
  };

  const getAttendanceStatus = (workerId, date) => {
    const rec = attendanceData.find(a => a.worker_id === workerId && a.date === date);
    return rec ? rec.status : '';
  };

  const isResting = (opId) => restingToday.some(r => r.operator_id === opId);

  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);

  const getAssignedOperator = (machineId, shift) => {
    const a = assignments.find(a => a.machine_id === machineId && a.shift_type === shift && a.is_active === 1);
    return a ? a : null;
  };

  // Group operators by position
  const operatorsByPosition = {};
  POSITIONS.forEach(pos => { operatorsByPosition[pos] = []; });
  operators.filter(o => o.is_active).forEach(op => {
    const pos = op.position || 'Operator';
    if (!operatorsByPosition[pos]) operatorsByPosition[pos] = [];
    operatorsByPosition[pos].push(op);
  });

  // Attendance table helpers
  const getDaysInMonth = () => {
    const [y, m] = attendanceMonth.split('-').map(Number);
    return new Date(y, m, 0).getDate();
  };

  const handlePlanChange = (operatorId, machineId, value) => {
    const key = `${operatorId}-${machineId}`;
    setPlanInputs(prev => ({ ...prev, [key]: parseFloat(value) || 0 }));
  };

  const saveDailyPlans = async () => {
    setSavingPlan(true);
    try {
      const plansToSave = [];
      Object.entries(planInputs).forEach(([key, planMeters]) => {
        if (planMeters > 0) {
          const [operatorId, machineId] = key.split('-');
          plansToSave.push({
            operator_id: parseInt(operatorId),
            machine_id: machineId,
            date: planDate,
            plan_meters: planMeters
          });
        }
      });
      if (plansToSave.length > 0) {
        const res = await fetch(`${API}/daily-plans/bulk`, {
          method: 'POST', headers,
          body: JSON.stringify({ date: planDate, plans: plansToSave })
        });
        if (res.ok) {
          alert('Planlar saqlandi!');
          fetchDailyPlans();
          emitRefresh();
        }
      }
    } catch (e) {
      alert('Xatolik yuz berdi');
    } finally {
      setSavingPlan(false);
    }
  };

  const renderWorkerRow = (op, shiftColor) => {
    const opAsgs = assignments.filter(a => a.operator_id === op.id && a.is_active === 1);
    const resting = isResting(op.id);
    const isOperator = op.position === 'Operator' || !op.position;

    // Calculate daily plan total for this operator
    let opPlanTotal = 0;
    let opActualTotal = 0;
    opAsgs.forEach(a => {
      const key = `${op.id}-${a.machine_id}`;
      const plan = dailyPlans[key];
      if (plan) {
        opPlanTotal += plan.plan_meters;
        opActualTotal += plan.actual_meters;
      }
    });

    return (
      <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
        <td style={tdStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <div style={{
              width: '32px', height: '32px', borderRadius: '8px',
              background: `${shiftColor}22`, display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.8rem', fontWeight: 800, color: shiftColor
            }}>{op.name.charAt(0).toUpperCase()}</div>
            <div>
              <span style={{ fontWeight: 600 }}>{op.name}</span>
              <div style={{ fontSize: '0.6rem', color: 'var(--text-muted)' }}>{op.position || 'Operator'}</div>
            </div>
          </div>
        </td>
        <td style={{ ...tdStyle, color: 'var(--text-muted)' }}>{op.phone || '-'}</td>
        <td style={tdStyle}>
          {isOperator ? (
            <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', alignItems: 'center' }}>
              {opAsgs.map(a => (
                <span key={a.id} style={{
                  padding: '2px 8px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 600,
                  background: 'rgba(168,85,247,0.15)', color: '#a855f7', cursor: 'pointer'
                }} onClick={() => handleUnassign(a.id)} title="Olib tashlash uchun bosing">
                  {a.machine_id} ×
                </span>
              ))}
              {opAsgs.length === 0 && <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>—</span>}
              <button onClick={() => openAssignForm(op.id, op.shift_type)} style={{
                padding: '4px 10px', borderRadius: '6px', fontSize: '0.65rem', fontWeight: 700,
                background: 'rgba(168,85,247,0.15)', color: '#a855f7', border: 'none', cursor: 'pointer',
                display: 'flex', alignItems: 'center', gap: '4px'
              }}>
                <Link size={12} /> Biriktirish
              </button>
            </div>
          ) : (
            <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>—</span>
          )}
        </td>
        <td style={tdStyle}>
          {isOperator && opPlanTotal > 0 ? (
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontWeight: 700, fontSize: '0.8rem' }}>{Math.round(opActualTotal)}/{Math.round(opPlanTotal)}</div>
              <div style={{
                fontSize: '0.65rem', fontWeight: 700,
                color: opPlanTotal > 0 && (opActualTotal / opPlanTotal) >= 1 ? '#22c55e' :
                       opPlanTotal > 0 && (opActualTotal / opPlanTotal) >= 0.8 ? '#f59e0b' : '#ef4444'
              }}>
                {opPlanTotal > 0 ? Math.round((opActualTotal / opPlanTotal) * 100) : 0}%
              </div>
            </div>
          ) : (
            <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>—</span>
          )}
        </td>
        <td style={tdStyle}>
          {resting ? (
            <span style={{ padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700, background: 'rgba(245,158,11,0.15)', color: '#f59e0b' }}>Dam olish</span>
          ) : (
            <span style={{ padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700, background: 'rgba(34,197,94,0.15)', color: '#22c55e' }}>Ishda</span>
          )}
        </td>
        <td style={tdStyle}>
          <div style={{ display: 'flex', gap: '4px' }}>
            <button onClick={() => handleDeleteOperator(op.id)} style={actionBtnStyle('#ef4444')} title="O'chirish">
              <Trash2 size={14} />
            </button>
          </div>
        </td>
      </tr>
    );
  };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '8px' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Users size={24} /> Ishchilar Boshqaruvi
        </h2>
        <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
          <button onClick={() => setShowAddOp(!showAddOp)} style={btnStyle('var(--primary)')}>
            <Plus size={16} /> Yangi Ishchi
          </button>
          <button onClick={() => setShowAttendance(!showAttendance)} style={btnStyle('#22c55e')}>
            <UserCheck size={16} /> Tabel
          </button>
        </div>
      </div>

      {/* Add Operator Form */}
      {showAddOp && (
        <div style={formCardStyle}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Ishchi Qo'shish</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
            <div>
              <label style={labelStyle}>Ism</label>
              <input className="input-field" style={inputSmStyle} value={opForm.name} onChange={e => setOpForm({ ...opForm, name: e.target.value })} placeholder="Ismni kiriting" />
            </div>
            <div>
              <label style={labelStyle}>Telefon</label>
              <input className="input-field" style={inputSmStyle} value={opForm.phone} onChange={e => setOpForm({ ...opForm, phone: e.target.value })} placeholder="+998..." />
            </div>
            <div>
              <label style={labelStyle}>Lavozim</label>
              <select className="input-field" style={inputSmStyle} value={opForm.position} onChange={e => setOpForm({ ...opForm, position: e.target.value })}>
                {POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div>
              <label style={labelStyle}>Smena</label>
              <div style={{ display: 'flex', gap: '8px', marginTop: '8px' }}>
                {['KUNDUZ', 'TUNGI'].map(s => (
                  <button key={s} onClick={() => setOpShift(s)} style={{
                    flex: 1, padding: '8px', borderRadius: '8px', border: '2px solid',
                    borderColor: opShift === s ? '#f59e0b' : 'rgba(255,255,255,0.1)',
                    background: opShift === s ? 'rgba(245,158,11,0.15)' : 'rgba(255,255,255,0.03)',
                    color: opShift === s ? '#f59e0b' : 'var(--text-muted)',
                    cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem'
                  }}>
                    {s === 'KUNDUZ' ? '☀️ Kunduzgi' : '🌙 Tungi'}
                  </button>
                ))}
              </div>
            </div>
          </div>
          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
            <button onClick={handleAddOperator} style={btnStyle('var(--primary)')}>Saqlash</button>
            <button onClick={() => setShowAddOp(false)} style={btnStyleSecondary()}>Bekor</button>
          </div>
        </div>
      )}

      {/* Assign Machine Form - per operator */}
      {showAssign && (
        <div style={formCardStyle}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
            Stanok Biriktirish — {operators.find(o => o.id === parseInt(selectedOperator))?.name || ''} ({shiftType === 'KUNDUZ' ? '☀️ Kunduzgi' : '🌙 Tungi'})
          </h3>
          <label style={labelStyle}>Stanoklarni tanlang ({selectedMachines.length} ta tanlandi)</label>
          <div style={{
            display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(55px, 1fr))',
            gap: '6px', marginTop: '8px', maxHeight: '300px', overflowY: 'auto',
            padding: '12px', background: 'rgba(0,0,0,0.3)', borderRadius: '12px'
          }}>
            {allMachineIds.map(id => {
              const isSelected = selectedMachines.includes(id);
              const assignedK = getAssignedOperator(id, 'KUNDUZ');
              const assignedT = getAssignedOperator(id, 'TUNGI');
              const isTaken = shiftType === 'KUNDUZ' ? assignedK : assignedT;
              const isMyMachine = isTaken && isTaken.operator_id === parseInt(selectedOperator);
              return (
                <button key={id} onClick={() => (isMyMachine || !isTaken) && toggleMachine(id)} style={{
                  padding: '8px 4px', borderRadius: '8px', border: '2px solid',
                  borderColor: isSelected ? '#a855f7' : isMyMachine ? '#22c55e' : isTaken ? '#ef4444' : 'rgba(255,255,255,0.1)',
                  background: isSelected ? 'rgba(168,85,247,0.2)' : isMyMachine ? 'rgba(34,197,94,0.15)' : isTaken ? 'rgba(239,68,68,0.1)' : 'rgba(255,255,255,0.03)',
                  color: isSelected ? '#a855f7' : isMyMachine ? '#22c55e' : isTaken ? '#ef4444' : 'var(--text-main)',
                  cursor: (isMyMachine || !isTaken) ? 'pointer' : 'not-allowed',
                  fontWeight: 700, fontSize: '0.7rem', opacity: (!isMyMachine && isTaken) ? 0.6 : 1
                }}>
                  {id}
                  {isTaken && <div style={{ fontSize: '0.5rem', marginTop: '2px', color: isMyMachine ? '#22c55e' : '#ef4444' }}>{isTaken.operator_name?.substring(0, 6)}</div>}
                </button>
              );
            })}
          </div>

          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
            <button onClick={handleAssign} style={btnStyle('#a855f7')}>
              Biriktirish ({selectedMachines.length} ta)
            </button>
            <button onClick={() => { setShowAssign(false); setSelectedMachines([]); setSelectedOperator(''); }} style={btnStyleSecondary()}>Bekor</button>
          </div>
        </div>
      )}

      {/* Daily Plan Section */}
      <div style={formCardStyle}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem', flexWrap: 'wrap', gap: '8px' }}>
          <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: '6px' }}>
            <Target size={18} /> Kunlik Reja ({planDate})
          </h3>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
            <input type="date" value={planDate} onChange={e => setPlanDate(e.target.value)}
              className="input-field" style={{ ...inputSmStyle, width: '160px' }} />
            {isNazoratchi && (
              <button onClick={saveDailyPlans} disabled={savingPlan} style={btnStyle('#22c55e')}>
                <Save size={14} /> {savingPlan ? 'Saqlanmoqda...' : 'Saqlash'}
              </button>
            )}
          </div>
        </div>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                <th style={thStyle}>Operator</th>
                <th style={thStyle}>Stanok</th>
                <th style={{ ...thStyle, textAlign: 'center' }}>Reja (metr)</th>
                <th style={{ ...thStyle, textAlign: 'center' }}>Bajarildi</th>
                <th style={{ ...thStyle, textAlign: 'center' }}>Holat</th>
              </tr>
            </thead>
            <tbody>
              {operators.filter(o => o.is_active && (o.position === 'Operator' || !o.position)).map(op => {
                const opAsgs = assignments.filter(a => a.operator_id === op.id && a.is_active === 1);
                if (opAsgs.length === 0) return null;

                return opAsgs.map((asg, idx) => {
                  const key = `${op.id}-${asg.machine_id}`;
                  const existingPlan = dailyPlans[key];
                  const currentValue = planInputs[key] || '';

                  return (
                    <tr key={key} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                      {idx === 0 && (
                        <td style={tdStyle} rowSpan={opAsgs.length}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <div style={{
                              width: '32px', height: '32px', borderRadius: '8px',
                              background: 'rgba(0,210,255,0.15)',
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              fontSize: '0.8rem', fontWeight: 800, color: 'var(--primary)'
                            }}>
                              {op.name.charAt(0).toUpperCase()}
                            </div>
                            <span style={{ fontWeight: 600 }}>{op.name}</span>
                          </div>
                        </td>
                      )}
                      <td style={tdStyle}>
                        <span style={{
                          padding: '4px 8px', borderRadius: '6px', fontSize: '0.75rem',
                          background: 'rgba(168,85,247,0.15)', color: '#a855f7', fontWeight: 600
                        }}>
                          {asg.machine_id}
                        </span>
                      </td>
                      <td style={{ ...tdStyle, textAlign: 'center' }}>
                        {isNazoratchi ? (
                          <input
                            type="number"
                            value={currentValue}
                            onChange={e => handlePlanChange(op.id, asg.machine_id, e.target.value)}
                            placeholder="0"
                            style={{
                              width: '100px', padding: '6px 10px', borderRadius: '6px',
                              border: '1px solid var(--panel-border)', background: 'rgba(255,255,255,0.03)',
                              color: 'var(--text-main)', textAlign: 'center', fontSize: '0.9rem'
                            }}
                          />
                        ) : (
                          <span style={{ fontWeight: 600 }}>{existingPlan ? Math.round(existingPlan.plan_meters) : '—'}</span>
                        )}
                      </td>
                      <td style={{ ...tdStyle, textAlign: 'center', fontWeight: 600 }}>
                        {existingPlan ? Math.round(existingPlan.actual_meters) : '—'}
                      </td>
                      <td style={{ ...tdStyle, textAlign: 'center' }}>
                        {existingPlan && (
                          <span style={{
                            padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem',
                            background: existingPlan.status === 'COMPLETED' ? 'rgba(34,197,94,0.15)' :
                                       existingPlan.status === 'INCOMPLETE' ? 'rgba(239,68,68,0.15)' : 'rgba(245,158,11,0.15)',
                            color: existingPlan.status === 'COMPLETED' ? '#22c55e' :
                                   existingPlan.status === 'INCOMPLETE' ? '#ef4444' : '#f59e0b',
                            fontWeight: 600
                          }}>
                            {existingPlan.status === 'COMPLETED' ? '✓ Bajarildi' :
                             existingPlan.status === 'INCOMPLETE' ? '✗ Bajarilmadi' : '⏳ Kutilmoqda'}
                          </span>
                        )}
                      </td>
                    </tr>
                  );
                });
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Attendance / Tabel Section */}
      {showAttendance && (
        <div style={formCardStyle}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 700 }}>
              <UserCheck size={18} style={{ marginRight: '6px', verticalAlign: 'middle' }} />
              Davomat (Tabel)
            </h3>
            <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
              <input type="month" value={attendanceMonth} onChange={e => setAttendanceMonth(e.target.value)}
                className="input-field" style={{ ...inputSmStyle, width: '160px' }} />
              <button onClick={exportAttendanceExcel} style={btnStyle('#22c55e')}>
                <Download size={14} /> Excel
              </button>
            </div>
          </div>
