{"tool":"newFileCreated","path":"frontend/src/components/MasterPanel.jsx","content":"import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Link, Users, UserCheck, Calendar, Download, Target, Save } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const POSITIONS = ['Operator', 'Master', 'Mexanik', 'Uzlavyaz', "Smena boshlig'i"];

const MasterPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [showAddOp, setShowAddOp] = useState(false);
  const [showAssign, setShowAssign] = useState(false);
  const [showAttendance, setShowAttendance] = useState(false);
  const [attendanceMonth, setAttendanceMonth] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  });
  const [attendanceData, setAttendanceData] = useState([]);

  const [opForm, setOpForm] = useState({ name: '', phone: '', position: 'Operator' });
  const [opShift, setOpShift] = useState('KUNDUZ');
  const [selectedOperator, setSelectedOperator] = useState('');
  const [selectedMachines, setSelectedMachines] = useState([]);
  const [shiftType, setShiftType] = useState('KUNDUZ');

  const [restingToday, setRestingToday] = useState([]);

  // Daily plan state
  const [planDate, setPlanDate] = useState(new Date().toISOString().split('T')[0]);
  const [dailyPlans, setDailyPlans] = useState({});
  const [planInputs, setPlanInputs] = useState({});
  const [savingPlan, setSavingPlan] = useState(false);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const isNazoratchi = user.role === 'NAZORATCHI' || user.role === 'ADMIN';

  const fetchData = async () => {
    try {
      const [opsRes, asgRes, restRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/assignments`, { headers }),
        fetch(`${API}/rest-days/today`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (asgRes.ok) setAssignments(await asgRes.json());
      if (restRes.ok) setRestingToday(await restRes.json());
    } catch (e) {}
  };

  const fetchDailyPlans = async () => {
    try {
      const res = await fetch(`${API}/daily-plans?date=${planDate}`, { headers });
      if (res.ok) {
        const plans = await res.json();
        const planMap = {};
        const inputMap = {};
        plans.forEach(p => {
          const key = `${p.operator_id}-${p.machine_id}`;
          planMap[key] = p;
          inputMap[key] = p.plan_meters;
        });
        setDailyPlans(planMap);
        setPlanInputs(inputMap);
      }
    } catch (e) {}
  };

  const fetchAttendance = async () => {
    try {
      const res = await fetch(`${API}/attendance?month=${attendanceMonth}`, { headers });
      if (res.ok) setAttendanceData(await res.json());
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, []);
  useEffect(() => { fetchDailyPlans(); }, [planDate]);
  useEffect(() => { fetchAttendance(); }, [attendanceMonth]);
  useEffect(() => { const h = () => { fetchData(); fetchDailyPlans(); }; window.addEventListener('app-refresh', h); return () => window.removeEventListener('app-refresh', h); }, []);

  const handleAddOperator = async () => {
    if (!opForm.name) return;
    try {
      const res = await fetch(`${API}/operators`, {
        method: 'POST', headers, body: JSON.stringify({ ...opForm, shift_type: opShift })
      });
      if (res.ok) {
        setOpForm({ name: '', phone: '', position: 'Operator' });
        setShowAddOp(false);
        fetchData();
        emitRefresh();
      } else {
        const data = await res.json();
        alert(data.detail || 'Xatolik yuz berdi');
      }
    } catch (e) { alert('Server xatoligi'); }
  };

  const handleDeleteOperator = async (id) => {
    if (!confirm('Ishchini ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/operators/${id}`, { method: 'DELETE', headers });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const toggleMachine = (id) => {
    setSelectedMachines(prev =>
      prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]
    );
  };

  const openAssignForm = (opId, opShiftType) => {
    setSelectedOperator(String(opId));
    setSelectedMachines([]);
    setShiftType(opShiftType || 'KUNDUZ');
    setShowAssign(true);
  };

  const handleAssign = async () => {
    if (!selectedOperator || selectedMachines.length === 0) return;
    try {
      const res = await fetch(`${API}/assignments`, {
        method: 'POST', headers,
        body: JSON.stringify({
          operator_id: parseInt(selectedOperator),
          machine_ids: selectedMachines,
          shift_type: shiftType
        })
      });
      if (res.ok) {
        setSelectedOperator('');
        setSelectedMachines([]);
        setShowAssign(false);
        fetchData();
        emitRefresh();
      }
    } catch (e) {}
  };

  const handleUnassign = async (id) => {
    try {
      await fetch(`${API}/assignments/${id}`, { method: 'DELETE', headers });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const handleSetAttendance = async (workerId, date, status) => {
    try {
      await fetch(`${API}/attendance`, {
        method: 'POST', headers,
        body: JSON.stringify({ worker_id: workerId, date, status })
      });
      fetchAttendance();
    } catch (e) {}
  };

  const exportAttendanceExcel = async () => {
    try {
      const res = await fetch(`${API}/attendance/export?month=${attendanceMonth}`, { headers });
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `tabel_${attendanceMonth}.xlsx`;
        a.click();
        window.URL.revokeObjectURL(url);
      }
    } catch (e) {}
  };

  const getAttendanceStatus = (workerId, date) => {
    const rec = attendanceData.find(a => a.worker_id === workerId && a.date === date);
    return rec ? rec.status : '';
  };

  const isResting = (opId) => restingToday.some(r => r.operator_id === opId);

  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);

  const getAssignedOperator = (machineId, shift) => {
    const a = assignments.find(a => a.machine_id === machineId && a.shift_type === shift && a.is_active === 1);
    return a ? a : null;
  };

  // Group operators by position
  const operatorsByPosition = {};
  POSITIONS.forEach(pos => { operatorsByPosition[pos] = []; });
  operators.filter(o => o.is_active).forEach(op => {
    const pos = op.position || 'Operator';
    if (!operatorsByPosition[pos]) operatorsByPosition[pos] = [];
    operatorsByPosition[pos].push(op);
  });

  // Attendance table helpers
  const getDaysInMonth = () => {
    const [y, m] = attendanceMonth.split('-').map(Number);
    return new Date(y, m, 0).getDate();
  };

  const handlePlanChange = (operatorId, machineId, value) => {
    const key = `${operatorId}-${machineId}`;
    setPlanInputs(prev => ({ ...prev, [key]: parseFloat(value) || 0 }));
  };

  const saveDailyPlans = async () => {
    setSavingPlan(true);
    try {
      const plansToSave = [];
      Object.entries(planInputs).forEach(([key, planMeters]) => {
        if (planMeters > 0) {
          const [operatorId, machineId] = key.split('-');
          plansToSave.push({
            operator_id: parseInt(operatorId),
            machine_id: machineId,
            date: planDate,
            plan_meters: planMeters
          });
        }
      });
      if (plansToSave.length > 0) {
        const res = await fetch(`${API}/daily-plans/bulk`, {
          method: 'POST', headers,
          body: JSON.stringify({ date: planDate, plans: plansToSave })
        });
        if (res.ok) {
          alert('Planlar saqlandi!');
          fetchDailyPlans();
          emitRefresh();
        }
      }
    } catch (e) {
      alert('Xatolik yuz berdi');
    } finally {
      setSavingPlan(false);
    }
  };

  const renderWorkerRow = (op, shiftColor) => {
    const opAsgs = assignments.filter(a => a.operator_id === op.id && a.is_active === 1);
