    const isOperator = op.position === 'Operator' || !op.position;

    return (
      <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
        <td style={tdStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{
              width: '36px', height: '36px', borderRadius: '10px', flexShrink: 0,
              background: `${shiftColor}22`, display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.85rem', fontWeight: 800, color: shiftColor
