            <div>
              <span style={{ fontWeight: 600, fontSize: '0.9rem' }}>{op.name}</span>
              <div style={{ fontSize: '0.65rem', color: 'var(--text-muted)' }}>{op.position || 'Operator'}</div>
            </div>
          </div>
        </td>
        <td style={{ ...tdStyle, color: 'var(--text-muted)', fontSize: '0.8rem' }}>{op.phone || '-'}</td>
        <td style={tdStyle}>
          {isOperator ? (
            <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap', alignItems: 'center' }}>
              {opAsgs.length > 0 ? opAsgs.map(a => (
                <span key={a.id} style={{
                  padding: '4px 10px', borderRadius: '8px', fontSize: '0.75rem', fontWeight: 600,
                  background: 'rgba(168,85,247,0.15)', color: '#a855f7', cursor: 'pointer',
