                <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem', fontStyle: 'italic' }}>Biriktirilmagan</span>
              )}
            </div>
          ) : (
            <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>—</span>
          )}
        </td>
        <td style={tdStyle}>
          {resting ? (
            <span style={{
              padding: '4px 12px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 700,
              background: 'rgba(245,158,11,0.15)', color: '#f59e0b'
            }}>Dam olish</span>
          ) : (
            <span style={{
              padding: '4px 12px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 700,
              background: 'rgba(34,197,94,0.15)', color: '#22c55e'
            }}>Ishda</span>
          )}
        </td>
        <td style={tdStyle}>
          <div style={{ display: 'flex', gap: '6px' }}>
            {isOperator && (
              <button onClick={() => openAssignForm(op)} style={{
                padding: '6px 12px', borderRadius: '8px', fontSize: '0.75rem', fontWeight: 600,
                background: 'rgba(168,85,247,0.15)', color: '#a855f7',
                border: '1px solid rgba(168,85,247,0.3)', cursor: 'pointer',
                display: 'flex', alignItems: 'center', gap: '4px'
              }}>
                <Link size={13} /> Biriktirish
              </button>
            )}
            <button onClick={() => handleDeleteOperator(op.id)} style={{
              padding: '6px', borderRadius: '8px',
              background: 'rgba(239,68,68,0.15)', color: '#ef4444',
              border: '1px solid rgba(239,68,68,0.3)', cursor: 'pointer',
              display: 'flex', alignItems: 'center'
            }}>
              <Trash2 size={14} />
            </button>
          </div>
        </td>
      </tr>
    );
  };

  return (
    <div style={{ padding: '1.5rem' }}>
