            <button onClick={() => setShowAddOp(false)} style={btnStyleSecondary()}>Bekor</button>
          </div>
        </div>
      )}

      {/* Assign Machine Form */}
      {showAssign && selectedOperator && (
        <div style={formCardStyle}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
            Stanok Biriktirish — <span style={{ color: '#a855f7' }}>{selectedOperator.name}</span>
            <span style={{ fontSize: '0.8rem', marginLeft: '8px', color: 'var(--text-muted)' }}>
              ({selectedOperator.shift_type === 'KUNDUZ' ? '☀️ Kunduzgi' : '🌙 Tungi'})
            </span>
          </h3>
          <label style={labelStyle}>Stanoklarni tanlang ({selectedMachines.length} ta tanlandi)</label>
          <div style={{
