{"tool":"newFileCreated","path":"frontend/src/components/NazoratchiPanel.jsx","content":"import React, { useState, useEffect } from 'react';
import { Calendar, ChevronLeft, ChevronRight } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const DAYS = ['Dush', 'Sesh', 'Chor', 'Pay', 'Jum', 'Shan', 'Yak'];
const DAYS_FULL = ['Dushanba', 'Seshanba', 'Chorshanba', 'Payshanba', 'Juma', 'Shanba', 'Yakshanba'];

function getMonday(d) {
  const date = new Date(d);
  const day = date.getDay();
  const diff = date.getDate() - day + (day === 0 ? -6 : 1);
  date.setDate(diff);
  return date.toISOString().split('T')[0];
}

const NazoratchiPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [restDays, setRestDays] = useState([]);
  const [weekStart, setWeekStart] = useState(getMonday(new Date()));

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const fetchData = async () => {
    try {
      const [opsRes, restRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/rest-days?week_start=${weekStart}`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (restRes.ok) setRestDays(await restRes.json());
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, [weekStart]);
  useEffect(() => {
    const h = () => fetchData();
    window.addEventListener('app-refresh', h);
    return () => window.removeEventListener('app-refresh', h);
  }, [weekStart]);

  const toggleRestDay = async (operatorId, dayOfWeek) => {
    try {
      await fetch(`${API}/rest-days`, {
        method: 'POST', headers,
        body: JSON.stringify({ operator_id: operatorId, day_of_week: dayOfWeek, week_start: weekStart })
      });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const isResting = (opId, dow) => restDays.some(r => r.operator_id === opId && r.day_of_week === dow);

  const shiftWeek = (offset) => {
    const d = new Date(weekStart);
    d.setDate(d.getDate() + offset * 7);
    setWeekStart(d.toISOString().split('T')[0]);
  };

  const weekLabel = () => {
    const start = new Date(weekStart);
    const end = new Date(weekStart);
    end.setDate(end.getDate() + 6);
    return `${start.toLocaleDateString('uz')} - ${end.toLocaleDateString('uz')}`;
  };

  const thStyle = { padding: '12px 16px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' };
  const tdStyle = { padding: '12px 16px', fontSize: '0.85rem', fontWeight: 500 };
  const navBtnStyle = { padding: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--panel-border)', borderRadius: '8px', color: 'var(--text-main)', cursor: 'pointer', display: 'flex', alignItems: 'center' };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '12px' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>
          <Calendar size={24} style={{ marginRight: '8px', verticalAlign: 'middle' }} />
          Dam Olish Jadvali
        </h2>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <button onClick={() => shiftWeek(-1)} style={navBtnStyle}><ChevronLeft size={16} /></button>
          <span style={{ fontSize: '0.9rem', fontWeight: 700, color: 'var(--primary)', minWidth: '200px', textAlign: 'center' }}>
            {weekLabel()}
          </span>
          <button onClick={() => shiftWeek(1)} style={navBtnStyle}><ChevronRight size={16} /></button>
        </div>
      </div>

      {/* Kunduzgi smena */}
      {['KUNDUZ', 'TUNGI'].map(shift => {
        const shiftOperators = operators.filter(o => o.is_active && o.shift_type === shift);
        const shiftColor = shift === 'KUNDUZ' ? '#f59e0b' : '#6366f1';
        const shiftLabel = shift === 'KUNDUZ' ? '☀️ Kunduzgi Smena' : '🌙 Tungi Smena';

        return (
          <div key={shift} style={{ marginBottom: '2rem' }}>
            <h3 style={{
              fontSize: '1.1rem', fontWeight: 800, color: shiftColor,
              marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px'
            }}>
              {shiftLabel}
              <span style={{
                fontSize: '0.7rem', background: `${shiftColor}22`, color: shiftColor,
                padding: '2px 10px', borderRadius: '12px', fontWeight: 700
              }}>{shiftOperators.length} ta</span>
            </h3>

            {shiftOperators.length === 0 ? (
              <div style={{
                padding: '2rem', textAlign: 'center', color: 'var(--text-muted)',
                background: 'var(--card)', borderRadius: '16px', border: '1px solid var(--panel-border)'
              }}>
                Ishchilar yo'q
              </div>
            ) : (
              <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                  <thead>
                    <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                      <th style={thStyle}>Operator</th>
                      {DAYS.map((d, i) => (
                        <th key={i} style={{ ...thStyle, textAlign: 'center' }}>{d}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {shiftOperators.map(op => (
                      <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                        <td style={tdStyle}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <div style={{
                              width: '32px', height: '32px', borderRadius: '8px',
                              background: `${shiftColor}22`,
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              fontSize: '0.8rem', fontWeight: 800, color: shiftColor
                            }}>
                              {op.name.charAt(0).toUpperCase()}
                            </div>
                            <span style={{ fontWeight: 600 }}>{op.name}</span>
                          </div>
                        </td>
                        {DAYS.map((_, dow) => {
                          const resting = isResting(op.id, dow);
                          return (
                            <td key={dow} style={{ ...tdStyle, textAlign: 'center' }}>
                              <button
                                onClick={() => toggleRestDay(op.id, dow)}
                                style={{
                                  width: '36px', height: '36px', borderRadius: '8px',
                                  border: resting ? '2px solid #fbbf24' : '1px solid var(--panel-border)',
                                  background: resting ? 'rgba(251,191,36,0.2)' : 'rgba(255,255,255,0.03)',
                                  color: resting ? '#fbbf24' : 'var(--text-muted)',
                                  cursor: 'pointer', fontSize: '1rem', fontWeight: 700,
                                  transition: 'all 0.2s'
                                }}
                                title={DAYS_FULL[dow]}
                              >
                                {resting ? '🛏️' : '○'}
                              </button>
                            </td>
                          );
                        })}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
};

