{"tool":"newFileCreated","path":"frontend/src/components/MasterPanel.jsx","content":"import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Link, Users, UserCheck, Download, Calendar } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const POSITIONS = ['Operator', 'Master', 'Mexanik', 'Uzlavyaz', "Smena boshlig'i"];

const MasterPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [showAddOp, setShowAddOp] = useState(false);
  const [opForm, setOpForm] = useState({ name: '', phone: '', position: 'Operator' });
  const [opShift, setOpShift] = useState('KUNDUZ');
  const [selectedMachines, setSelectedMachines] = useState([]);
  const [assignTarget, setAssignTarget] = useState(null);
  const [restingToday, setRestingToday] = useState([]);
  const [attendanceMonth, setAttendanceMonth] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  });
  const [attendanceData, setAttendanceData] = useState([]);
  const [dailyPlans, setDailyPlans] = useState([]);
  const [planDate, setPlanDate] = useState(new Date().toISOString().split('T')[0]);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const fetchData = async () => {
    try {
      const [opsRes, asgRes, restRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/assignments`, { headers }),
        fetch(`${API}/rest-days/today`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (asgRes.ok) setAssignments(await asgRes.json());
      if (restRes.ok) setRestingToday(await restRes.json());
    } catch (e) {}
  };

  const fetchAttendance = async () => {
    try {
      const res = await fetch(`${API}/attendance?month=${attendanceMonth}`, { headers });
      if (res.ok) setAttendanceData(await res.json());
    } catch (e) {}
  };

  const fetchDailyPlans = async () => {
    try {
      const res = await fetch(`${API}/daily-plans?date=${planDate}`, { headers });
      if (res.ok) setDailyPlans(await res.json());
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, []);
  useEffect(() => { fetchAttendance(); }, [attendanceMonth]);
  useEffect(() => { fetchDailyPlans(); }, [planDate]);
  useEffect(() => {
    const h = () => { fetchData(); fetchAttendance(); fetchDailyPlans(); };
    window.addEventListener('app-refresh', h);
    return () => window.removeEventListener('app-refresh', h);
  }, []);

  const handleAddOperator = async () => {
    if (!opForm.name) return;
    try {
      const res = await fetch(`${API}/operators`, {
        method: 'POST', headers, body: JSON.stringify({ ...opForm, shift_type: opShift })
      });
      if (res.ok) {
        setOpForm({ name: '', phone: '', position: 'Operator' });
        setShowAddOp(false);
        fetchData();
      }
    } catch (e) {}
  };

  const handleDeleteOperator = async (id) => {
    if (!confirm('O\'chirishni tasdiqlaysizmi?')) return;
    try {
      await fetch(`${API}/operators/${id}`, { method: 'DELETE', headers });
      fetchData();
    } catch (e) {}
  };

  const handleAssign = async () => {
    if (!assignTarget || selectedMachines.length === 0) return;
    try {
      await fetch(`${API}/assignments`, {
        method: 'POST', headers,
        body: JSON.stringify({ operator_id: assignTarget, machine_ids: selectedMachines })
      });
      setSelectedMachines([]);
      setAssignTarget(null);
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const handleUnassign = async (assignmentId) => {
    try {
      await fetch(`${API}/assignments/${assignmentId}`, { method: 'DELETE', headers });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const setAttendance = async (workerId, dateStr, status) => {
    try {
      await fetch(`${API}/attendance`, {
        method: 'POST', headers,
        body: JSON.stringify({ worker_id: workerId, date: dateStr, status })
      });
      fetchAttendance();
    } catch (e) {}
  };

  const isResting = (opId) => restingToday.some(r => r.operator_id === opId);

  const getAttendanceStatus = (workerId, dateStr) => {
    const rec = attendanceData.find(a => a.worker_id === workerId && a.date === dateStr);
    return rec ? rec.status : null;
  };

  const getOpPlanInfo = (opId) => {
    const opPlans = dailyPlans.filter(p => p.operator_id === opId);
    if (opPlans.length === 0) return null;
    const totalPlan = opPlans.reduce((s, p) => s + p.plan_meters, 0);
    const totalActual = opPlans.reduce((s, p) => s + p.actual_meters, 0);
    const pct = totalPlan > 0 ? Math.round((totalActual / totalPlan) * 100) : 0;
    return { totalPlan, totalActual, pct };
  };

  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);
  const workers = operators.filter(o => o.is_active);
  const assignableOperators = workers.filter(o => o.position === 'Operator' || !o.position);

  const todayStr = new Date().toISOString().split('T')[0];
  const year = parseInt(attendanceMonth.split('-')[0]);
  const mon = parseInt(attendanceMonth.split('-')[1]);
  const daysInMonth = new Date(year, mon, 0).getDate();

  const thStyle = { padding: '12px 16px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' };
  const tdStyle = { padding: '12px 16px', fontSize: '0.85rem', fontWeight: 500 };
  const labelStyle = { fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600, marginBottom: '4px', display: 'block' };
  const inputSmStyle = { padding: '8px 12px', borderRadius: '8px', border: '1px solid var(--panel-border)', background: 'rgba(255,255,255,0.05)', color: 'var(--text-main)', fontSize: '0.85rem', width: '100%' };
  const actionBtnStyle = (color) => ({ padding: '6px', borderRadius: '6px', border: 'none', background: `${color}22`, color, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' });
  const tableCardStyle = { background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden' };

  const renderWorkerRow = (op, shiftColor) => {
    const opAsgs = assignments.filter(a => a.operator_id === op.id && a.is_active === 1);
    const resting = isResting(op.id);
    const isOperator = op.position === 'Operator' || !op.position;
    const planInfo = getOpPlanInfo(op.id);

    return (
      <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
        <td style={tdStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <div style={{
              width: '32px', height: '32px', borderRadius: '8px',
              background: `${shiftColor}22`, display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.8rem', fontWeight: 800, color: shiftColor
            }}>{op.name.charAt(0).toUpperCase()}</div>
            <div>
              <span style={{ fontWeight: 600 }}>{op.name}</span>
              <div style={{ fontSize: '0.6rem', color: 'var(--text-muted)' }}>{op.position || 'Operator'}</div>
            </div>
          </div>
        </td>
        <td style={{ ...tdStyle, color: 'var(--text-muted)' }}>{op.phone || '-'}</td>
        <td style={tdStyle}>
          {isOperator ? (
            <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', alignItems: 'center' }}>
              {opAsgs.map(a => (
                <span key={a.id} style={{
                  padding: '2px 8px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 600,
                  background: 'rgba(168,85,247,0.15)', color: '#a855f7', cursor: 'pointer'
                }} onClick={() => handleUnassign(a.id)} title="Olib tashlash uchun bosing">
                  {a.machine_id} ×
                </span>
              ))}
              <button onClick={() => { setAssignTarget(op.id); setSelectedMachines([]); }} style={{
                padding: '4px 10px', borderRadius: '6px', border: '1px dashed rgba(168,85,247,0.4)',
                background: 'rgba(168,85,247,0.1)', color: '#a855f7', cursor: 'pointer',
                fontSize: '0.7rem', fontWeight: 600
              }}>
                <Link size={10} style={{ marginRight: '2px', verticalAlign: 'middle' }} /> Biriktirish
              </button>
            </div>
          ) : (
            <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>—</span>
          )}
        </td>
        <td style={tdStyle}>
          {planInfo ? (
            <div style={{ fontSize: '0.75rem' }}>
              <span style={{ color: '#00d2ff', fontWeight: 700 }}>{Math.round(planInfo.totalActual)}m</span>
              <span style={{ color: 'var(--text-muted)' }}> / {Math.round(planInfo.totalPlan)}m</span>
              <span style={{
                marginLeft: '6px', padding: '2px 6px', borderRadius: '4px', fontSize: '0.65rem', fontWeight: 700,
                background: planInfo.pct >= 100 ? 'rgba(34,197,94,0.2)' : planInfo.pct >= 50 ? 'rgba(255,234,0,0.2)' : 'rgba(255,49,49,0.2)',
                color: planInfo.pct >= 100 ? '#22c55e' : planInfo.pct >= 50 ? '#ffea00' : '#ff3131'
              }}>{planInfo.pct}%</span>
            </div>
          ) : (
            <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>—</span>
          )}
        </td>
        <td style={tdStyle}>
          {resting ? (
            <span style={{ padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700, background: 'rgba(245,158,11,0.15)', color: '#f59e0b' }}>Dam olish</span>
          ) : (
            <span style={{ padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700, background: 'rgba(34,197,94,0.15)', color: '#22c55e' }}>Ishda</span>
          )}
        </td>
        <td style={tdStyle}>
          <button onClick={() => handleDeleteOperator(op.id)} style={actionBtnStyle('#ef4444')} title="O'chirish">
            <Trash2 size={14} />
          </button>
        </td>
      </tr>
    );
  };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '8px' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Users size={24} /> Ishchilar Boshqaruvi
        </h2>
        <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
          {(user.role === 'ADMIN' || user.role === 'MASTER') && (
            <button onClick={() => setShowAddOp(!showAddOp)} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
              background: 'var(--primary)', color: '#0a0f1a', border: 'none', borderRadius: '10px',
              cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
            }}>
              <Plus size={16} /> Yangi Ishchi
            </button>
          )}
        </div>
      </div>

      {/* Assign Modal */}
      {assignTarget && (
        <div className="modal-overlay" onClick={() => setAssignTarget(null)}>
          <div className="modal-content" onClick={e => e.stopPropagation()} style={{ maxWidth: '500px' }}>
            <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
              Stanok biriktirish — {operators.find(o => o.id === assignTarget)?.name}
            </h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(6, 1fr)', gap: '6px', maxHeight: '300px', overflowY: 'auto', padding: '4px' }}>
              {allMachineIds.map(mid => {
                const isSelected = selectedMachines.includes(mid);
                return (
                  <button key={mid} onClick={() => setSelectedMachines(prev => isSelected ? prev.filter(m => m !== mid) : [...prev, mid])} style={{
                    padding: '8px 4px', borderRadius: '8px',
                    border: `2px solid ${isSelected ? '#a855f7' : 'rgba(255,255,255,0.1)'}`,
                    background: isSelected ? 'rgba(168,85,247,0.2)' : 'rgba(255,255,255,0.03)',
                    color: isSelected ? '#a855f7' : 'var(--text-muted)',
                    cursor: 'pointer', fontWeight: 700, fontSize: '0.75rem', transition: 'all 0.2s'
                  }}>{mid}</button>
                );
              })}
            </div>
            <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
              <button onClick={handleAssign} disabled={selectedMachines.length === 0} style={{
                flex: 1, padding: '12px', borderRadius: '10px', border: 'none',
                background: selectedMachines.length === 0 ? 'rgba(168,85,247,0.3)' : '#a855f7',
                color: 'white', cursor: 'pointer', fontWeight: 700
              }}>Biriktirish ({selectedMachines.length})</button>
              <button onClick={() => setAssignTarget(null)} style={{
                padding: '12px 20px', borderRadius: '10px', border: '1px solid var(--panel-border)',
                background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)', cursor: 'pointer', fontWeight: 600
              }}>Bekor</button>
            </div>
          </div>
        </div>
      )}

      {/* Add Operator Form */}
      {showAddOp && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Ishchi Qo'shish</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '12px' }}>
            <div>
              <label style={labelStyle}>Ism</label>
              <input className="input-field" style={inputSmStyle} value={opForm.name} onChange={e => setOpForm({ ...opForm, name: e.target.value })} placeholder="Ism familya" />
            </div>
            <div>
              <label style={labelStyle}>Telefon</label>
              <input className="input-field" style={inputSmStyle} value={opForm.phone} onChange={e => setOpForm({ ...opForm, phone: e.target.value })} placeholder="+998..." />
            </div>
            <div>
              <label style={labelStyle}>Lavozim</label>
              <select className="input-field" style={inputSmStyle} value={opForm.position} onChange={e => setOpForm({ ...opForm, position: e.target.value })}>
                {POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div>
              <label style={labelStyle}>Smena</label>
              <div style={{ display: 'flex', gap: '8px' }}>
                {['KUNDUZ', 'TUNGI'].map(s => (
                  <button key={s} onClick={() => setOpShift(s)} style={{
                    flex: 1, padding: '8px', borderRadius: '8px', border: `2px solid ${opShift === s ? (s === 'KUNDUZ' ? '#f59e0b' : '#6366f1') : 'rgba(255,255,255,0.1)'}`,
                    background: opShift === s ? (s === 'KUNDUZ' ? 'rgba(245,158,11,0.15)' : 'rgba(99,102,241,0.15)') : 'rgba(255,255,255,0.03)',
                    color: opShift === s ? (s === 'KUNDUZ' ? '#f59e0b' : '#6366f1') : 'var(--text-muted)',
                    cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem'
                  }}>{s === 'KUNDUZ' ? '☀️ Kunduzgi' : '🌙 Tungi'}</button>
                ))}
              </div>
            </div>
          </div>
          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
            <button onClick={handleAddOperator} style={{
              padding: '10px 20px', background: 'var(--primary)', color: '#0a0f1a', border: 'none',
              borderRadius: '10px', cursor: 'pointer', fontWeight: 700
            }}>Qo'shish</button>
            <button onClick={() => setShowAddOp(false)} style={{
              padding: '10px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)',
              border: '1px solid var(--panel-border)', borderRadius: '10px', cursor: 'pointer', fontWeight: 600
            }}>Bekor</button>
          </div>
        </div>
      )}

      {/* Operator Tables by Shift */}
      {['KUNDUZ', 'TUNGI'].map(shift => {
        const shiftWorkers = workers.filter(o => (o.shift_type || 'KUNDUZ') === shift);
        const shiftColor = shift === 'KUNDUZ' ? '#f59e0b' : '#6366f1';
        const shiftLabel = shift === 'KUNDUZ' ? '☀️ Kunduzgi Smena' : '🌙 Tungi Smena';

        return (
          <div key={shift} style={{ marginBottom: '2rem' }}>
            <h3 style={{
              fontSize: '1.1rem', fontWeight: 800, color: shiftColor,
              marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px'
            }}>
              {shiftLabel}
              <span style={{
                fontSize: '0.7rem', background: `${shiftColor}22`, color: shiftColor,
                padding: '2px 10px', borderRadius: '12px', fontWeight: 700
              }}>{shiftWorkers.length} ta</span>
            </h3>

            {shiftWorkers.length === 0 ? (
              <div style={{
                padding: '2rem', textAlign: 'center', color: 'var(--text-muted)',
                background: 'var(--card)', borderRadius: '16px', border: '1px solid var(--panel-border)'
              }}>Ishchilar yo'q</div>
            ) : (
              <div style={tableCardStyle}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                  <thead>
                    <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                      <th style={thStyle}>Ism</th>
                      <th style={thStyle}>Telefon</th>
                      <th style={thStyle}>Biriktirilgan Stanoklar</th>
                      <th style={thStyle}>Bugungi Reja</th>
                      <th style={thStyle}>Status</th>
                      <th style={thStyle}>Amallar</th>
                    </tr>
                  </thead>
                  <tbody>
                    {shiftWorkers.map(op => renderWorkerRow(op, shiftColor))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        );
      })}

      {/* Attendance Section */}
      <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', paddingTop: '1.5rem', marginTop: '1rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem', flexWrap: 'wrap', gap: '8px' }}>
          <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '8px' }}>
            <UserCheck size={20} /> Davomat (Tabel)
          </h3>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
            <input type="month" value={attendanceMonth} onChange={e => setAttendanceMonth(e.target.value)}
              className="input-field" style={{ width: '160px' }} />
            <button onClick={async () => {
              try {
                const res = await fetch(`${API}/attendance/export?month=${attendanceMonth}`, { headers });
                if (res.ok) {
                  const blob = await res.blob();
                  const url = window.URL.createObjectURL(blob);
                  const a = document.createElement('a');
                  a.href = url; a.download = `tabel_${attendanceMonth}.xlsx`; a.click();
                  window.URL.revokeObjectURL(url);
                }
              } catch (e) {}
            }} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
              background: 'rgba(34,197,94,0.15)', color: '#22c55e', border: 'none', borderRadius: '10px',
              cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem', textDecoration: 'none'
            }}>
              <Download size={16} /> Excel
            </button>
          </div>
        </div>

        {/* Attendance Table */}
        <div style={tableCardStyle}>
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '800px' }}>
              <thead>
                <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                  <th style={{ ...thStyle, position: 'sticky', left: 0, background: '#1e293b', zIndex: 5, minWidth: '150px' }}>Ism</th>
                  {Array.from({ length: daysInMonth }, (_, i) => {
                    const d = i + 1;
                    const dateStr = `${attendanceMonth}-${String(d).padStart(2, '0')}`;
                    const isToday = dateStr === todayStr;
                    return (
                      <th key={d} style={{
                        ...thStyle, textAlign: 'center', padding: '8px 4px', minWidth: '36px',
                        background: isToday ? 'rgba(0,210,255,0.1)' : '#1e293b',
                        color: isToday ? '#00d2ff' : 'var(--text-muted)',
                        position: 'sticky', top: 0, zIndex: 3
                      }}>{d}</th>
                    );
                  })}
                  <th style={{ ...thStyle, textAlign: 'center', position: 'sticky', top: 0, right: 0, background: '#1e293b', zIndex: 5 }}>Jami</th>
                </tr>
              </thead>
              <tbody>
                {workers.map(op => {
                  let presentCount = 0;
                  return (
                    <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                      <td style={{
                        ...tdStyle, position: 'sticky', left: 0, background: 'var(--card)', zIndex: 2,
                        fontWeight: 600, fontSize: '0.8rem'
                      }}>{op.name}</td>
                      {Array.from({ length: daysInMonth }, (_, i) => {
                        const d = i + 1;
                        const dateStr = `${attendanceMonth}-${String(d).padStart(2, '0')}`;
                        const status = getAttendanceStatus(op.id, dateStr);
                        const isToday = dateStr === todayStr;
                        if (status === 'PRESENT') presentCount++;

                        const cellBg = status === 'PRESENT' ? 'rgba(34,197,94,0.2)' :
                          status === 'ABSENT' ? 'rgba(255,49,49,0.2)' :
                          status === 'REST' ? 'rgba(245,158,11,0.2)' : 'transparent';
                        const cellColor = status === 'PRESENT' ? '#22c55e' :
                          status === 'ABSENT' ? '#ff3131' :
                          status === 'REST' ? '#f59e0b' : 'var(--text-muted)';

                        return (
                          <td key={d} style={{
                            textAlign: 'center', padding: '4px 2px', fontSize: '0.75rem', fontWeight: 700,
                            background: isToday ? 'rgba(0,210,255,0.05)' : 'transparent',
                            cursor: 'pointer', transition: '0.15s'
                          }}
                            onClick={() => {
                              const next = !status ? 'PRESENT' : status === 'PRESENT' ? 'ABSENT' : status === 'ABSENT' ? 'REST' : null;
                              if (next) setAttendance(op.id, dateStr, next);
                              else setAttendance(op.id, dateStr, 'PRESENT');
                            }}
                            title={`${op.name} - ${dateStr}`}
                          >
                            {status === 'PRESENT' ? (
                              <span style={{ color: cellColor, fontWeight: 800 }}>+</span>
                            ) : status === 'ABSENT' ? (
                              <span style={{ color: cellColor, fontWeight: 800 }}>−</span>
                            ) : status === 'REST' ? (
                              <span style={{ color: cellColor, fontSize: '0.7rem' }}>D</span>
                            ) : (
                              <span style={{ color: 'rgba(255,255,255,0.1)', fontSize: '0.6rem' }}>·</span>
                            )}
                          </td>
                        );
                      })}
                      <td style={{
                        ...tdStyle, textAlign: 'center', fontWeight: 800, fontSize: '0.8rem',
                        position: 'sticky', right: 0, background: 'var(--card)', zIndex: 2,
                        color: '#00d2ff'
                      }}>{presentCount}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

