                    border: `2px solid ${isSelected ? '#a855f7' : isAssigned ? 'rgba(255,49,49,0.3)' : 'rgba(255,255,255,0.1)'}`,
                    background: isSelected ? 'rgba(168,85,247,0.2)' : isAssigned ? 'rgba(255,49,49,0.1)' : 'rgba(255,255,255,0.03)',
                    color: isSelected ? '#a855f7' : isAssigned ? '#ff3131' : 'var(--text-muted)',
                    cursor: isAssigned ? 'not-allowed' : 'pointer', fontWeight: 700, fontSize: '0.75rem',
                    opacity: isAssigned ? 0.5 : 1
                  }}>
                    {isSelected ? '✓ ' : ''}{mId}
                  </button>
                );
              })}
            </div>
            <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
              <button onClick={handleAssign} disabled={selectedMachines.length === 0} style={{
                flex: 1, padding: '12px', background: selectedMachines.length === 0 ? 'rgba(168,85,247,0.3)' : '#a855f7',
                color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700
              }}>Biriktirish ({selectedMachines.length})</button>
              <button onClick={() => { setShowAssign(false); setSelectedMachines([]); }} style={{
                padding: '12px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)',
                border: '1px solid var(--panel-border)', borderRadius: '10px', cursor: 'pointer', fontWeight: 600
              }}>Bekor</button>
            </div>
          </div>
        </div>
      )}

      {/* Operators Tab */}
      {activeTab === 'operators' && (
        <div>
          {['KUNDUZ', 'TUNGI'].map(shift => {
            const shiftWorkers = workers.filter(w => w.shift_type === shift);
            const shiftColor = shift === 'KUNDUZ' ? '#f59e0b' : '#6366f1';
            const shiftLabel = shift === 'KUNDUZ' ? '☀️ Kunduzgi Smena' : '🌙 Tungi Smena';
            return (
              <div key={shift} style={{ marginBottom: '1.5rem' }}>
                <h3 style={{
                  fontSize: '1.1rem', fontWeight: 800, color: shiftColor,
                  marginBottom: '0.75rem', display: 'flex', alignItems: 'center', gap: '8px'
                }}>
                  {shiftLabel}
                  <span style={{
                    fontSize: '0.7rem', background: `${shiftColor}22`, color: shiftColor,
                    padding: '2px 10px', borderRadius: '12px', fontWeight: 700
                  }}>{shiftWorkers.length} ta</span>
                </h3>
                {shiftWorkers.length === 0 ? (
                  <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-muted)', background: 'var(--card)', borderRadius: '16px', border: '1px solid var(--panel-border)' }}>
                    Ishchilar yo'q
                  </div>
                ) : (
                  <div style={tableCardStyle}>
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                      <thead>
                        <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                          <th style={thStyle}>Ism</th>
                          <th style={thStyle}>Telefon</th>
                          <th style={thStyle}>Biriktirilgan Stanoklar</th>
                          <th style={thStyle}>Status</th>
                          <th style={thStyle}>Amallar</th>
                        </tr>
                      </thead>
                      <tbody>
                        {shiftWorkers.map(op => renderWorkerRow(op, shiftColor))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Attendance Tab */}
      {activeTab === 'attendance' && (
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '1rem' }}>
            <input type="month" value={attendanceMonth} onChange={e => setAttendanceMonth(e.target.value)}
              className="input-field" style={{ width: '160px' }} />
            <button onClick={async () => {
              try {
                const res = await fetch(`${API}/attendance/export?month=${attendanceMonth}`, { headers });
                if (res.ok) {
                  const blob = await res.blob();
                  const url = window.URL.createObjectURL(blob);
                  const a = document.createElement('a');
                  a.href = url; a.download = `tabel_${attendanceMonth}.xlsx`; a.click();
                  window.URL.revokeObjectURL(url);
                }
              } catch (e) {}
            }} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
              background: 'rgba(34,197,94,0.15)', color: '#22c55e', border: 'none', borderRadius: '10px',
              cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem'
            }}>
              <Download size={16} /> Excel
            </button>
          </div>

          <div style={tableCardStyle}>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '800px' }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                    <th style={{ ...thStyle, position: 'sticky', left: 0, background: '#1e293b', zIndex: 5, minWidth: '150px' }}>Ism</th>
                    {Array.from({ length: daysInMonth }, (_, i) => {
                      const d = i + 1;
                      const dateStr = `${attendanceMonth}-${String(d).padStart(2, '0')}`;
                      const isToday = dateStr === todayStr;
                      const dayOfWeek = new Date(dateStr).getDay();
                      const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
                      return (
                        <th key={d} style={{
                          ...thStyle, textAlign: 'center', padding: '8px 4px', minWidth: '36px',
                          background: isToday ? 'rgba(0,210,255,0.1)' : isWeekend ? 'rgba(245,158,11,0.05)' : '#1e293b',
                          color: isToday ? '#00d2ff' : isWeekend ? '#f59e0b' : 'var(--text-muted)',
                          position: 'sticky', top: 0, zIndex: 3
                        }}>
                          <div style={{ fontSize: '0.6rem' }}>{DAYS[dayOfWeek === 0 ? 6 : dayOfWeek - 1]}</div>
                          <div>{d}</div>
                        </th>
                      );
                    })}
                    <th style={{ ...thStyle, textAlign: 'center', position: 'sticky', right: 0, background: '#1e293b', zIndex: 4 }}>Jami</th>
                  </tr>
                </thead>
                <tbody>
                  {workers.map(op => {
                    let presentCount = 0;
                    return (
                      <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                        <td style={{ ...tdStyle, position: 'sticky', left: 0, background: 'var(--card)', zIndex: 2, fontWeight: 600 }}>
                          {op.name}
                        </td>
                        {Array.from({ length: daysInMonth }, (_, i) => {
                          const d = i + 1;
                          const dateStr = `${attendanceMonth}-${String(d).padStart(2, '0')}`;
                          const status = getAttendanceStatus(op.id, dateStr);
                          const isToday = dateStr === todayStr;
                          if (status === 'PRESENT') presentCount++;

                          const cellBg = status === 'PRESENT' ? 'rgba(34,197,94,0.2)' :
                            status === 'ABSENT' ? 'rgba(255,49,49,0.2)' :
                            status === 'REST' ? 'rgba(245,158,11,0.2)' : 'transparent';
                          const cellColor = status === 'PRESENT' ? '#22c55e' :
                            status === 'ABSENT' ? '#ff3131' :
                            status === 'REST' ? '#f59e0b' : 'var(--text-muted)';

                          return (
                            <td key={d} style={{
                              textAlign: 'center', padding: '4px 2px', fontSize: '0.75rem', fontWeight: 700,
                              background: isToday ? 'rgba(0,210,255,0.05)' : 'transparent',
                              cursor: 'pointer', transition: '0.15s'
                            }}
                              onClick={() => {
                                const next = !status ? 'PRESENT' : status === 'PRESENT' ? 'ABSENT' : status === 'ABSENT' ? 'REST' : null;
                                if (next) setAttendance(op.id, dateStr, next);
                                else setAttendance(op.id, dateStr, 'PRESENT');
                              }}
                              title={`${op.name} - ${dateStr}`}
                            >
                              {status === 'PRESENT' ? (
                                <span style={{ color: cellColor, fontWeight: 800 }}>+</span>
                              ) : status === 'ABSENT' ? (
                                <span style={{ color: cellColor, fontWeight: 800 }}>−</span>
                              ) : status === 'REST' ? (
                                <span style={{ color: cellColor, fontSize: '0.7rem' }}>D</span>
                              ) : (
                                <span style={{ color: 'rgba(255,255,255,0.1)', fontSize: '0.6rem' }}>·</span>
                              )}
                            </td>
                          );
                        })}
                        <td style={{
                          ...tdStyle, textAlign: 'center', fontWeight: 800, fontSize: '0.8rem',
                          position: 'sticky', right: 0, background: 'var(--card)', zIndex: 2,
                          color: '#00d2ff'
                        }}>{presentCount}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Rest Days Tab */}
      {activeTab === 'rest' && (
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '1rem' }}>
            <button onClick={() => {
              const d = new Date(weekStart);
              d.setDate(d.getDate() - 7);
              setWeekStart(d.toISOString().split('T')[0]);
            }} style={{
              padding: '8px 12px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--panel-border)',
              borderRadius: '8px', color: 'var(--text-main)', cursor: 'pointer', fontWeight: 700
            }}>←</button>
            <span style={{ fontSize: '0.9rem', fontWeight: 700, color: 'var(--primary)', minWidth: '200px', textAlign: 'center' }}>
              {(() => {
                const start = new Date(weekStart);
                const end = new Date(weekStart);
                end.setDate(end.getDate() + 6);
                return `${start.toLocaleDateString('uz')} - ${end.toLocaleDateString('uz')}`;
              })()}
            </span>
            <button onClick={() => {
              const d = new Date(weekStart);
              d.setDate(d.getDate() + 7);
              setWeekStart(d.toISOString().split('T')[0]);
            }} style={{
              padding: '8px 12px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--panel-border)',
              borderRadius: '8px', color: 'var(--text-main)', cursor: 'pointer', fontWeight: 700
            }}>→</button>
          </div>

          {['KUNDUZ', 'TUNGI'].map(shift => {
            const shiftOperators = operators.filter(o => o.is_active && o.shift_type === shift);
            const shiftColor = shift === 'KUNDUZ' ? '#f59e0b' : '#6366f1';
            const shiftLabel = shift === 'KUNDUZ' ? '☀️ Kunduzgi Smena' : '🌙 Tungi Smena';

            return (
              <div key={shift} style={{ marginBottom: '2rem' }}>
                <h3 style={{
                  fontSize: '1.1rem', fontWeight: 800, color: shiftColor,
                  marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px'
                }}>
                  {shiftLabel}
                  <span style={{
                    fontSize: '0.7rem', background: `${shiftColor}22`, color: shiftColor,
                    padding: '2px 10px', borderRadius: '12px', fontWeight: 700
                  }}>{shiftOperators.length} ta</span>
                </h3>

                {shiftOperators.length === 0 ? (
                  <div style={{
                    padding: '2rem', textAlign: 'center', color: 'var(--text-muted)',
                    background: 'var(--card)', borderRadius: '16px', border: '1px solid var(--panel-border)'
                  }}>
                    Ishchilar yo'q
                  </div>
                ) : (
                  <div style={tableCardStyle}>
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                      <thead>
                        <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
                          <th style={thStyle}>Operator</th>
                          {DAYS.map((d, i) => (
                            <th key={i} style={{ ...thStyle, textAlign: 'center' }}>{d}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {shiftOperators.map(op => (
                          <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                            <td style={tdStyle}>
                              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                <div style={{
                                  width: '32px', height: '32px', borderRadius: '8px',
                                  background: `${shiftColor}22`,
                                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                                  fontSize: '0.8rem', fontWeight: 800, color: shiftColor
                                }}>
                                  {op.name.charAt(0).toUpperCase()}
                                </div>
                                <span style={{ fontWeight: 600 }}>{op.name}</span>
                              </div>
                            </td>
                            {DAYS.map((_, dow) => {
                              const resting = restingToday.some(r => r.operator_id === op.id && r.day_of_week === dow);
                              return (
                                <td key={dow} style={{ ...tdStyle, textAlign: 'center' }}>
                                  <button
                                    onClick={async () => {
                                      try {
                                        await fetch(`${API}/rest-days`, {
                                          method: 'POST', headers,
                                          body: JSON.stringify({ operator_id: op.id, day_of_week: dow, week_start: weekStart })
                                        });
                                        fetchData();
                                        emitRefresh();
                                      } catch (e) {}
                                    }}
                                    style={{
                                      width: '36px', height: '36px', borderRadius: '8px',
                                      border: resting ? '2px solid #fbbf24' : '1px solid var(--panel-border)',
                                      background: resting ? 'rgba(251,191,36,0.2)' : 'rgba(255,255,255,0.03)',
                                      color: resting ? '#fbbf24' : 'var(--text-muted)',
                                      cursor: 'pointer', fontSize: '1rem', fontWeight: 700,
                                      transition: 'all 0.2s'
                                    }}
                                    title={DAYS_FULL[dow]}
                                  >
                                    {resting ? '🛏️' : '○'}
                                  </button>
                                </td>
                              );
                            })}
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

